-- STEP 1: query [kommuner]
SELECT kommunenummer, kommunenavn, objid, omrade FROM kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE '%kristiansand%';

-- STEP BOUNDARY --

-- STEP 2: query [stormflohavniva]
SELECT objid, malemetode, opphav, sikkerhetsklasseflom FROM stormflohavniva_bd7c84ed67254396b81e18b48ee0f525.stormflo200ar_klimaarna LIMIT 5;

-- STEP BOUNDARY --

-- STEP 3: query [statistiskrutenett1km]
SELECT COUNT(DISTINCT g.id) AS count_1km_cells FROM public.statistiskrutenett1km AS g JOIN stormflohavniva_bd7c84ed67254396b81e18b48ee0f525.stormflo200ar_klimaarna AS s ON ST_Intersects(g.geom, s.omrade) JOIN kommuner_627ee106072240e99d2b21ec4717bf01.kommune AS k ON ST_Intersects(g.geom, k.omrade) WHERE k.kommunenummer = '4204';
